"use client";
import { useEffect, useState } from "react";
import { getLogo } from "@/lib/utils";
import { useSession } from "next-auth/react";
import {
    Wallet,
    ArrowUpRight,
    ArrowDownLeft,
    Clock,
    Eye,
    EyeOff
} from "lucide-react";

export default function DashboardPage() {
    const { data: session } = useSession();
    const [summary, setSummary] = useState<{ balance: number; walletDetails: any[] } | null>(null);
    const [transactions, setTransactions] = useState<any[]>([]);
    const [loading, setLoading] = useState(true);
    
    // Fitur Privasi: Sensor Saldo
    const [showBalance, setShowBalance] = useState(false);

    // Ambil nickname dari session (misal: Stan Fredheric -> Stan)
    const nickname = session?.user?.name?.split(" ")[0] || "User";

    useEffect(() => {
        const fetchData = async () => {
            try {
                const resSummary = await fetch("/api/dashboard/summary");
                if (resSummary.ok) {
                    const dataSummary = await resSummary.json();
                    setSummary(dataSummary);
                }

                const resTx = await fetch("/api/transactions/recent");
                if (resTx.ok) {
                    const dataTx = await resTx.json();
                    setTransactions(dataTx);
                }
            } catch (err) {
                console.error("Error fetching data:", err);
            } finally {
                setLoading(false);
            }
        };
        fetchData();
    }, []);

    // Fungsi helper untuk sensor
    const formatCurrency = (amount: number) => {
        return showBalance
            ? `Rp ${amount.toLocaleString("id-ID")}` 
            : "Rp ••••••••";
    };

    // --- LOADING STATE ---
    if (loading) return (
        <div className="flex items-center justify-center min-h-screen bg-slate-50">
            <p className="text-slate-500 font-medium animate-pulse text-xl">
                Sabar ya {nickname}, lagi ngitung duit...
            </p>
        </div>
    );

    // --- MAIN RENDER ---
    return (
        <div className="p-4 md:p-8 bg-slate-50 min-h-screen text-slate-800">
            <div className="max-w-7xl mx-auto">
                <header className="mb-8 flex justify-between items-end">
                    <div>
                        <h1 className="text-2xl font-bold">Selamat Datang Kembali, {nickname}! 👋</h1>
                        <p className="text-slate-500">Berikut adalah ringkasan finansial ET-Pareto kamu.</p>
                    </div>
                </header>

                <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
                    
                    {/* KOLOM KIRI (2/3 Space) */}
                    <div className="lg:col-span-2 space-y-8">
                        
                        {/* Kartu Saldo Utama */}
                        <div className="bg-gradient-to-br from-blue-600 to-blue-700 p-8 rounded-3xl shadow-lg shadow-blue-100 text-white relative overflow-hidden">
                            <div className="relative z-10">
                                <div className="flex justify-between items-center max-w-[220px]">
                                    <p className="text-blue-100 text-sm font-medium">Total Saldo (Semua Akun)</p>
                                    <button 
                                        onClick={() => setShowBalance(!showBalance)}
                                        className="text-blue-200 hover:text-white transition-colors bg-white/10 p-1.5 rounded-lg"
                                    >
                                        {showBalance ? <EyeOff size={18} /> : <Eye size={18} />}
                                    </button>
                                </div>
                                <h2 className="text-4xl md:text-5xl font-bold mt-2">
                                    {formatCurrency(summary?.balance || 0)}
                                </h2>
                            </div>
                            <div className="absolute right-[-20px] bottom-[-20px] opacity-10">
                                <Wallet size={150} />
                            </div>
                        </div>

                        {/* Daftar Akun */}
                        <div>
                            <h3 className="text-lg font-bold mb-4 flex items-center gap-2 text-slate-700">
                                <Wallet className="text-blue-500" size={20} />
                                Daftar Akun Kamu
                            </h3>
                            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                {summary?.walletDetails?.map((wallet, index) => (
                                    <div key={index} className="bg-white p-5 rounded-2xl border border-slate-100 shadow-sm flex justify-between items-center hover:border-blue-200 hover:shadow-md transition-all cursor-default">
                                        <div>
                                            <p className="font-bold text-slate-700">{wallet.name}</p>
                                            <p className="text-[10px] text-slate-400 uppercase font-bold tracking-widest">{wallet.type}</p>
                                        </div>
                                        <p className="font-bold text-slate-600">
                                            {formatCurrency(wallet.balance)}
                                        </p>
                                    </div>
                                ))}
                            </div>
                        </div>
                    </div>

                    {/* KOLOM KANAN (1/3 Space) */}
                    <div className="space-y-6">
                        <div className="bg-white p-6 rounded-3xl shadow-sm border border-slate-100 h-full">
                            <h3 className="text-lg font-bold text-slate-800 mb-6 flex items-center gap-2">
                                <Clock className="text-slate-400" size={20} />
                                Transaksi Terakhir
                            </h3>

                            <div className="space-y-5">
                                {transactions.length > 0 ? transactions.map((tx, idx) => (
                                    <div key={idx} className="flex justify-between items-center group">
                                        <div className="flex gap-4 items-center">
                                            <div className={`p-3 rounded-xl ${tx.type === 'INCOME' ? 'bg-green-50 text-green-600' : 'bg-red-50 text-red-500'}`}>
                                                {tx.type === 'INCOME' ? <ArrowUpRight size={18} /> : <ArrowDownLeft size={18} />}
                                            </div>
                                            <div>
                                                <p className="text-sm font-bold text-slate-700 line-clamp-1">{tx.description || tx.category?.name}</p>
                                                <p className="text-[10px] text-slate-400">{new Date(tx.createdAt).toLocaleDateString("id-ID")}</p>
                                            </div>
                                        </div>
                                        <p className={`text-sm font-bold ${tx.type === 'INCOME' ? 'text-green-600' : 'text-red-500'}`}>
                                            {tx.type === 'INCOME' ? '+' : '-'} {tx.amount.toLocaleString("id-ID")}
                                        </p>
                                    </div>
                                )) : (
                                    <div className="text-center py-10">
                                        <p className="text-slate-400 text-sm italic">Belum ada jajan hari ini...</p>
                                    </div>
                                )}
                            </div>

                            <button className="w-full mt-8 py-3 text-sm text-blue-600 font-bold bg-blue-50 rounded-2xl hover:bg-blue-100 transition-all">
                                Lihat Semua Riwayat
                            </button>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
}